script.text:

/* <flatten type="Javascript"> */
function load$GridDeductible(g) {
  g.add_itemValueChanged(onChange$GridDeductible);
  g.add_onResponseComplete(onChange$GridDeductible$ResponseComplete);
  g.add_commandEvent(onChange$GridDeductible$ExecuteCommand);
  g.$a = {
    ps_no: '[ps_no]:=[ps_no_nt]*[$ty_gia]',
    ps_co: '[ps_co]:=[ps_co_nt]*[$ty_gia]',
    ps_no_nt: '[ps_no_nt]:= [ps_no_nt]',
    ps_co_nt: '[ps_co_nt]:= [ps_co_nt]'
  };
  udf$Detail$(g);
}
function dispose$GridDeductible(g) {
  g.$a = null;
  try {g.remove_commandEvent(onChange$GridDeductible$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridDeductible);} catch (ex) {}
  try {g.remove_onResponseComplete(onChange$GridDeductible$ResponseComplete);} catch (ex) {}
}
function onChange$GridDeductibleAccount(o) {o.grid.request(o, 'Account', 'Account', ['tk'], o);}
function onChange$GridDeductible(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'ps_no_nt':
      g.executeExpression(o, ['[ps_co_nt]:=0']);
      g.validExpression(o, [g.$a.ps_no, g.$a.ps_co], null, null, 'ps_co_nt');
      break;
    case 'ps_co_nt':
      g.executeExpression(o, ['[ps_no_nt]:=0']);
      g.validExpression(o, [g.$a.ps_co, g.$a.ps_no], null, null, null);
      break;
    case 'ps_no':
      g.executeExpression(o, ['[ps_co]:=0']);
      break;
    case 'ps_co':
      g.executeExpression(o, ['[ps_no]:=0']);
      break;
    default:
      break;
  }
}
function onChange$GridDeductible$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
    case 'BeforeInsertRow':
    case 'BeforeCloneRow':
      var v = f.getItemValue('loai_ct');
      if('259'.indexOf(v) == -1) e.type.cancelEvent = true;
      break;
    case 'AfterInsertRow':
      if (g._rowCount > 1) {
        var a = {n: ['ps_co_nt', 'ps_no_nt', 'ps_co', 'ps_no'], v: [0, 0, 0, 0]};
        for (var i = 0; i < a.n.length; i++) a.v[i] = g.sum(a.n[i]);
        var d1 = a.v[1] - a.v[0], d2 = a.v[3] - a.v[2];
        if (d1 > 0) {
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_co_nt'), d1);
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_co'), d2);
        } else {
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_no_nt'), -d1);
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_no'), -d2);
        }
      }
      break;
    case 'Check':
      g.validRowExpression('ma_kh', '(![tk_cn]) || ([ma_kh] != "")');
	    break;
    default:
      break;
  }
}

function onChange$GridDeductible$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
   case 'Account':
      g.setItemGridBehavior(o, [['tk_cn', result[0].Value, '', false]]);
      break;
    default:
      break;
  }
}
/* </flatten> */
